async function(ctx) {
  const selector = "[class*='ring-warning']";
  const notifyId = '5878981847';
  await ctx.wait(5000);
  await ctx.click("button[class*='bg-info']");
  const deadline = Date.now() + 60000;
  let text = '';
  while (Date.now() < deadline) {
    const el = ctx.query(selector);
    text = el ? el.textContent.trim() : '';
    if (text.includes('3h 59m')) {
      return {
        success: true,
        message: `重启成功，时间已重置：${text}`,
        variables: { shutdownTime: text, tg_notify_chat_id: notifyId }
      };
    }
    await ctx.wait(10000);
  }
  return {
    success: false,
    message: `时间未重置，当前：${text || '未读取到时间'}`,
    keepOpen: true,
    variables: { shutdownTime: text, tg_notify_chat_id: notifyId }
  };
}
